INSERT INTO coaching.phase_order_slot (key, name, description, phase_id, order_index, freshness_sensitivity, subrole_key)
SELECT v.key, v.name, v.description, sp.id, v.order_index, v.freshness_sensitivity, v.subrole_key
FROM coaching.session_phase sp
CROSS JOIN (VALUES
  ('cone_sprint_mechanics', 'Cone Sprint Mechanics', 'Cone Sprint Mechanics — Cone March Line.', 321, 2, 'locomotion_sprint_mechanics'),
  ('cone_skip_rhythm', 'Cone Skip Rhythm', 'Cone Sprint Mechanics — Cone Skip Rhythm Build.', 322, 2, 'balance_coordination_rhythm'),
  ('curvilinear_sprint_mechanics', 'Curvilinear Sprint Mechanics', 'Curvilinear Speed — Curve Run Around Cone Arc.', 323, 2, 'locomotion_sprint_mechanics'),
  ('planned_multidirectional_pattern', 'Planned Multidirectional Pattern', 'Planned COD Pattern — W Drill Backpedal Cuts.', 324, 2, 'balance_coordination_rhythm'),
  ('weave_spatial_control', 'Weave Spatial Control', 'Curvilinear Cone Control — Slalom Weave Run.', 325, 2, 'balance_coordination_rhythm'),
  ('curvilinear_spatial_control', 'Curvilinear Spatial Control', 'Curvilinear Cone Control — Figure-8 Cone Run.', 326, 2, 'balance_coordination_rhythm'),
  ('curvilinear_reactive_game', 'Curvilinear Reactive Game', 'Curvilinear Cone Control — Circle Cone Chase.', 327, 2, 'perception_action_reactive_movement'),
  ('multidirectional_spatial_control', 'Multidirectional Spatial Control', 'Multidirectional Cone Control — Hexagon Cone Attack Drill.', 328, 2, 'balance_coordination_rhythm'),
  ('partner_mirror_agility', 'Partner Mirror Agility', 'Reactive Cone Agility — Partner Mirror Shuffle Box.', 329, 2, 'perception_action_reactive_movement'),
  ('coach_callout_reactive_skill', 'Coach Callout Reactive Skill', 'Reactive Cone Agility — Color/Number Cone Reaction Drill.', 330, 2, 'perception_action_reactive_movement'),
  ('partner_tag_agility', 'Partner Tag Agility', 'Reactive Cone Agility — Shadow Tag Cone Channel.', 331, 2, 'perception_action_reactive_movement')
) AS v(key, name, description, order_index, freshness_sensitivity, subrole_key)
WHERE sp.key = 'movement_intelligence'
ON CONFLICT (key) DO UPDATE SET
  name = EXCLUDED.name,
  description = EXCLUDED.description,
  phase_id = EXCLUDED.phase_id,
  order_index = EXCLUDED.order_index,
  freshness_sensitivity = EXCLUDED.freshness_sensitivity,
  subrole_key = EXCLUDED.subrole_key;

