-- Insert 46 cone drill exercises
INSERT INTO coaching.exercise (
  facility_id, name, slug, description, sport_id, skill_level, age_min,
  default_sets, default_reps, default_work_seconds, default_rest_seconds, est_seconds_per_set,
  is_published, visibility, participant_structure,
  card_summary, coach_language, athlete_language,
  movement_family, primary_phase_key, phase_subrole, primary_order_slot,
  movement_requirements, coaching_execution
)
SELECT
  f.id,
  d.name, d.slug, d.description,
  (SELECT id FROM coaching.sport WHERE key = 'fitness'),
  d.skill::public.skill_level,
  d.age_min,
  d.sets, d.reps, d.work, d.rest, d.est,
  TRUE, 'facility', d.participant,
  d.summary, d.coach_lang, d.athlete_lang,
  d.family, d.phase_key, d.subrole, d.slot,
  d.req::jsonb, d.exec::jsonb
FROM (VALUES
  ('Cone March Line', 'cone-march-line', 'Cone March Line is a cone-based athletic drill focused on posture, arm action, rhythm, and front-side mechanics. Place 6-10 cones in a straight line about one walking stride apart. It belongs in the library because it is easy to set up, easy to coach, and scalable from youth development to advanced field/court athletes.', 'BEGINNER', 6, 2, 3, NULL, 45, 45, 'individual', 'Cone drill for posture, arm action, rhythm, and front-side mechanics. Best when coached as Movement Intelligence with the drill dose matched to the session phase.', 'Primary phase: Movement Intelligence. Primary subrole: locomotion_sprint_mechanics. Technical learning while fresh; quality stops when timing or posture fades. Progress only when the route, posture, and stop/cut quality are repeatable.', 'Move smooth, stay balanced, and learn the route before going fast.', 'Cone Sprint Mechanics', 'movement_intelligence', 'locomotion_sprint_mechanics', 'cone_sprint_mechanics', '{"primary_joint_actions":["ankle_stiffness","hip_flexion_extension","knee_flexion_extension"],"primary_tissues":["calves","quadriceps","hamstrings","glutes","adductors"],"primary_motor_control_demands":["spatial_orientation","visual_navigation"],"postural_shape":"athletic stance with ribs stacked over pelvis during cuts and stops","breathing_demand":"rhythmic; no breath holding during approach, cut, or stop","balance_demand":"dynamic","coordination_demand":"multi-step cone navigation with clean arm-leg timing","impact_level":1}'::jsonb, '{"movement_description":"Cone March Line uses cones to create a clear movement problem: posture, arm action, rhythm, and front-side mechanics. Place 6-10 cones in a straight line about one walking stride apart. The coach selects speed, spacing, and rest so the drill trains movement intelligence rather than junk fatigue.","setup":["Place 6-10 cones in a straight line about one walking stride apart.","Use a flat, dry surface with at least 3-5 yards of safe run-out beyond the final cone.","Walk the route once so the athlete understands the entry, target, and finish standard."],"execution_steps":["Start in an athletic stance with eyes up and weight balanced through the whole foot.","Perform the cone march line route at teaching speed first, then progress only if rhythm stays clean.","Brake, cut, or turn with hips loaded, knees tracking over toes, and the trunk under control.","Finish through the final cone or stick the final position exactly as prescribed.","Reset fully before the next rep; stop the set if posture, route accuracy, or braking quality fades."],"coach_cues":["Eyes up; see the cone early, not at the last step.","Push the ground away; do not reach and pull with the lead foot.","Load the hip before changing direction.","Quiet shoulders, violent arms when the drill calls for speed.","Win the shape before chasing the time."],"athlete_cues":["See it early.","Brake low and strong.","Push out of the cut.","Fast feet, quiet body."],"breathing_cues":["Breathe naturally during setup.","Do not hold the breath through the cut or stop.","Use one calm breath to reset before the next rep."],"common_faults":["Standing tall into the stop or cut.","Reaching the plant foot too far outside the hip.","Knee collapsing inside the foot.","Looking down at the cone instead of scanning ahead.","Turning quality reps into conditioning volume."],"quality_gate":["Route is correct without coach rescue.","Final stop or turn is balanced with no extra hop unless the drill calls for a run-through.","Knee tracks over toes on the plant leg.","Athlete can repeat the same shape on both sides.","Speed increases only after control is repeatable."],"stop_signs":["Pain in ankle, knee, hip, back, or groin.","Slipping surface or cones sliding into the athlete path.","Repeated uncontrolled knee valgus or trunk collapse.","Athlete cannot remember route or react safely.","Fatigue changes braking mechanics."]}'::jsonb),
  ('Cone Skip Rhythm Build', 'cone-skip-rhythm-build', 'Cone Skip Rhythm Build is a cone-based athletic drill focused on elastic rhythm, posture, and timing without racing. Place 6-8 cones in a line; spacing allows relaxed skip contacts. It belongs in the library because it is easy to set up, easy to coach, and scalable from youth development to advanced field/court athletes.', 'BEGINNER', 6, 2, 3, NULL, 45, 45, 'individual', 'Cone drill for elastic rhythm, posture, and timing without racing. Best when coached as Movement Intelligence with the drill dose matched to the session phase.', 'Primary phase: Movement Intelligence. Primary subrole: balance_coordination_rhythm. Technical learning while fresh; quality stops when timing or posture fades. Progress only when the route, posture, and stop/cut quality are repeatable.', 'Move smooth, stay balanced, and learn the route before going fast.', 'Cone Sprint Mechanics', 'movement_intelligence', 'balance_coordination_rhythm', 'cone_skip_rhythm', '{"primary_joint_actions":["ankle_stiffness","hip_flexion_extension","knee_flexion_extension"],"primary_tissues":["calves","quadriceps","hamstrings","glutes","adductors"],"primary_motor_control_demands":["spatial_orientation","visual_navigation"],"postural_shape":"athletic stance with ribs stacked over pelvis during cuts and stops","breathing_demand":"rhythmic; no breath holding during approach, cut, or stop","balance_demand":"dynamic","coordination_demand":"multi-step cone navigation with clean arm-leg timing","impact_level":2}'::jsonb, '{"movement_description":"Cone Skip Rhythm Build uses cones to create a clear movement problem: elastic rhythm, posture, and timing without racing. Place 6-8 cones in a line; spacing allows relaxed skip contacts. The coach selects speed, spacing, and rest so the drill trains movement intelligence rather than junk fatigue.","setup":["Place 6-8 cones in a line; spacing allows relaxed skip contacts.","Use a flat, dry surface with at least 3-5 yards of safe run-out beyond the final cone.","Walk the route once so the athlete understands the entry, target, and finish standard."],"execution_steps":["Start in an athletic stance with eyes up and weight balanced through the whole foot.","Perform the cone skip rhythm build route at teaching speed first, then progress only if rhythm stays clean.","Brake, cut, or turn with hips loaded, knees tracking over toes, and the trunk under control.","Finish through the final cone or stick the final position exactly as prescribed.","Reset fully before the next rep; stop the set if posture, route accuracy, or braking quality fades."],"coach_cues":["Eyes up; see the cone early, not at the last step.","Push the ground away; do not reach and pull with the lead foot.","Load the hip before changing direction.","Quiet shoulders, violent arms when the drill calls for speed.","Win the shape before chasing the time."],"athlete_cues":["See it early.","Brake low and strong.","Push out of the cut.","Fast feet, quiet body."],"breathing_cues":["Breathe naturally during setup.","Do not hold the breath through the cut or stop.","Use one calm breath to reset before the next rep."],"common_faults":["Standing tall into the stop or cut.","Reaching the plant foot too far outside the hip.","Knee collapsing inside the foot.","Looking down at the cone instead of scanning ahead.","Turning quality reps into conditioning volume."],"quality_gate":["Route is correct without coach rescue.","Final stop or turn is balanced with no extra hop unless the drill calls for a run-through.","Knee tracks over toes on the plant leg.","Athlete can repeat the same shape on both sides.","Speed increases only after control is repeatable."],"stop_signs":["Pain in ankle, knee, hip, back, or groin.","Slipping surface or cones sliding into the athlete path.","Repeated uncontrolled knee valgus or trunk collapse.","Athlete cannot remember route or react safely.","Fatigue changes braking mechanics."]}'::jsonb),
  ('A-Skip Through Cone Gates', 'a-skip-through-cone-gates', 'A-Skip Through Cone Gates is a cone-based athletic drill focused on front-side sprint mechanics and posture through visual gates. Use paired cones as 6-8 gates, each about one skip stride apart. It belongs in the library because it is easy to set up, easy to coach, and scalable from youth development to advanced field/court athletes.', 'BEGINNER', 7, 2, 3, NULL, 45, 45, 'individual', 'Cone drill for front-side sprint mechanics and posture through visual gates. Best when coached as Movement Intelligence with the drill dose matched to the session phase.', 'Primary phase: Movement Intelligence. Primary subrole: locomotion_sprint_mechanics. Technical learning while fresh; quality stops when timing or posture fades. Progress only when the route, posture, and stop/cut quality are repeatable.', 'Move smooth, stay balanced, and learn the route before going fast.', 'Cone Sprint Mechanics', 'movement_intelligence', 'locomotion_sprint_mechanics', 'cone_sprint_mechanics', '{"primary_joint_actions":["ankle_stiffness","hip_flexion_extension","knee_flexion_extension"],"primary_tissues":["calves","quadriceps","hamstrings","glutes","adductors"],"primary_motor_control_demands":["spatial_orientation","visual_navigation"],"postural_shape":"athletic stance with ribs stacked over pelvis during cuts and stops","breathing_demand":"rhythmic; no breath holding during approach, cut, or stop","balance_demand":"dynamic","coordination_demand":"multi-step cone navigation with clean arm-leg timing","impact_level":2}'::jsonb, '{"movement_description":"A-Skip Through Cone Gates uses cones to create a clear movement problem: front-side sprint mechanics and posture through visual gates. Use paired cones as 6-8 gates, each about one skip stride apart. The coach selects speed, spacing, and rest so the drill trains movement intelligence rather than junk fatigue.","setup":["Use paired cones as 6-8 gates, each about one skip stride apart.","Use a flat, dry surface with at least 3-5 yards of safe run-out beyond the final cone.","Walk the route once so the athlete understands the entry, target, and finish standard."],"execution_steps":["Start in an athletic stance with eyes up and weight balanced through the whole foot.","Perform the a-skip through cone gates route at teaching speed first, then progress only if rhythm stays clean.","Brake, cut, or turn with hips loaded, knees tracking over toes, and the trunk under control.","Finish through the final cone or stick the final position exactly as prescribed.","Reset fully before the next rep; stop the set if posture, route accuracy, or braking quality fades."],"coach_cues":["Eyes up; see the cone early, not at the last step.","Push the ground away; do not reach and pull with the lead foot.","Load the hip before changing direction.","Quiet shoulders, violent arms when the drill calls for speed.","Win the shape before chasing the time."],"athlete_cues":["See it early.","Brake low and strong.","Push out of the cut.","Fast feet, quiet body."],"breathing_cues":["Breathe naturally during setup.","Do not hold the breath through the cut or stop.","Use one calm breath to reset before the next rep."],"common_faults":["Standing tall into the stop or cut.","Reaching the plant foot too far outside the hip.","Knee collapsing inside the foot.","Looking down at the cone instead of scanning ahead.","Turning quality reps into conditioning volume."],"quality_gate":["Route is correct without coach rescue.","Final stop or turn is balanced with no extra hop unless the drill calls for a run-through.","Knee tracks over toes on the plant leg.","Athlete can repeat the same shape on both sides.","Speed increases only after control is repeatable."],"stop_signs":["Pain in ankle, knee, hip, back, or groin.","Slipping surface or cones sliding into the athlete path.","Repeated uncontrolled knee valgus or trunk collapse.","Athlete cannot remember route or react safely.","Fatigue changes braking mechanics."]}'::jsonb),
  ('Falling Start to 10-Yard Cone', 'falling-start-to-10-yard-cone', 'Falling Start to 10-Yard Cone is a cone-based athletic drill focused on first-step projection and acceleration posture. One start line cone and one finish cone 10 yards away. It belongs in the library because it is easy to set up, easy to coach, and scalable from youth development to advanced field/court athletes.', 'BEGINNER', 9, 3, 2, NULL, 90, 20, 'individual', 'Cone drill for first-step projection and acceleration posture. Best when coached as Output with the drill dose matched to the session phase.', 'Primary phase: Output. Primary subrole: acceleration_start_speed. High intent, low volume, full rest; tired reps become conditioning rather than power. Progress only when the route, posture, and stop/cut quality are repeatable.', 'Attack the cone, brake under control, then explode out clean.', 'Cone Acceleration', 'output', 'acceleration_start_speed', 'short_acceleration_start', '{"primary_joint_actions":["ankle_stiffness","hip_flexion_extension","knee_flexion_extension"],"primary_tissues":["calves","quadriceps","hamstrings","glutes","adductors"],"primary_motor_control_demands":["spatial_orientation","visual_navigation"],"postural_shape":"athletic stance with ribs stacked over pelvis during cuts and stops","breathing_demand":"rhythmic; no breath holding during approach, cut, or stop","balance_demand":"dynamic-high-speed","coordination_demand":"multi-step cone navigation with clean arm-leg timing","impact_level":3}'::jsonb, '{"movement_description":"Falling Start to 10-Yard Cone uses cones to create a clear movement problem: first-step projection and acceleration posture. One start line cone and one finish cone 10 yards away. The coach selects speed, spacing, and rest so the drill trains output rather than junk fatigue.","setup":["One start line cone and one finish cone 10 yards away.","Use a flat, dry surface with at least 3-5 yards of safe run-out beyond the final cone.","Walk the route once so the athlete understands the entry, target, and finish standard."],"execution_steps":["Start in an athletic stance with eyes up and weight balanced through the whole foot.","Perform the falling start to 10-yard cone route at the prescribed speed while staying inside the cone constraints.","Brake, cut, or turn with hips loaded, knees tracking over toes, and the trunk under control.","Finish through the final cone or stick the final position exactly as prescribed.","Reset fully before the next rep; stop the set if posture, route accuracy, or braking quality fades."],"coach_cues":["Eyes up; see the cone early, not at the last step.","Push the ground away; do not reach and pull with the lead foot.","Load the hip before changing direction.","Quiet shoulders, violent arms when the drill calls for speed.","Win the shape before chasing the time."],"athlete_cues":["See it early.","Brake low and strong.","Push out of the cut.","Fast feet, quiet body."],"breathing_cues":["Breathe naturally during setup.","Do not hold the breath through the cut or stop.","Use one calm breath to reset before the next rep."],"common_faults":["Standing tall into the stop or cut.","Reaching the plant foot too far outside the hip.","Knee collapsing inside the foot.","Looking down at the cone instead of scanning ahead.","Turning quality reps into conditioning volume."],"quality_gate":["Route is correct without coach rescue.","Final stop or turn is balanced with no extra hop unless the drill calls for a run-through.","Knee tracks over toes on the plant leg.","Athlete can repeat the same shape on both sides.","Speed increases only after control is repeatable."],"stop_signs":["Pain in ankle, knee, hip, back, or groin.","Slipping surface or cones sliding into the athlete path.","Repeated uncontrolled knee valgus or trunk collapse.","Athlete cannot remember route or react safely.","Fatigue changes braking mechanics."]}'::jsonb),
  ('Split-Stance 10-Yard Acceleration', 'split-stance-10-yard-acceleration', 'Split-Stance 10-Yard Acceleration is a cone-based athletic drill focused on explosive first two steps from a staggered stance. One start cone and one finish cone 10 yards away. It belongs in the library because it is easy to set up, easy to coach, and scalable from youth development to advanced field/court athletes.', 'BEGINNER', 9, 3, 2, NULL, 90, 20, 'individual', 'Cone drill for explosive first two steps from a staggered stance. Best when coached as Output with the drill dose matched to the session phase.', 'Primary phase: Output. Primary subrole: acceleration_start_speed. High intent, low volume, full rest; tired reps become conditioning rather than power. Progress only when the route, posture, and stop/cut quality are repeatable.', 'Attack the cone, brake under control, then explode out clean.', 'Cone Acceleration', 'output', 'acceleration_start_speed', 'short_acceleration_start', '{"primary_joint_actions":["ankle_stiffness","hip_flexion_extension","knee_flexion_extension"],"primary_tissues":["calves","quadriceps","hamstrings","glutes","adductors"],"primary_motor_control_demands":["spatial_orientation","visual_navigation"],"postural_shape":"athletic stance with ribs stacked over pelvis during cuts and stops","breathing_demand":"rhythmic; no breath holding during approach, cut, or stop","balance_demand":"dynamic-high-speed","coordination_demand":"multi-step cone navigation with clean arm-leg timing","impact_level":3}'::jsonb, '{"movement_description":"Split-Stance 10-Yard Acceleration uses cones to create a clear movement problem: explosive first two steps from a staggered stance. One start cone and one finish cone 10 yards away. The coach selects speed, spacing, and rest so the drill trains output rather than junk fatigue.","setup":["One start cone and one finish cone 10 yards away.","Use a flat, dry surface with at least 3-5 yards of safe run-out beyond the final cone.","Walk the rou