  ('Ball Drop/Point-and-Sprint Cone Reaction', 'ball-drop-point-and-sprint-cone-reaction', 'Ball Drop/Point-and-Sprint Cone Reaction is a cone-based athletic drill focused on visual cue reaction into short acceleration. Athlete starts between cones; coach drops a ball or points to a cone target. It belongs in the library because it is easy to set up, easy to coach, and scalable from youth development to advanced field/court athletes.', 'BEGINNER', 9, 3, 2, NULL, 90, 20, 'individual', 'Cone drill for visual cue reaction into short acceleration. Best when coached as Output with the drill dose matched to the session phase.', 'Primary phase: Output. Primary subrole: acceleration_start_speed. High intent, low volume, full rest; tired reps become conditioning rather than power. Progress only when the route, posture, and stop/cut quality are repeatable.', 'Attack the cone, brake under control, then explode out clean.', 'Reactive Cone Agility', 'output', 'acceleration_start_speed', 'visual_reaction_acceleration', '{"primary_joint_actions":["ankle_stiffness","hip_flexion_extension","knee_flexion_extension"],"primary_tissues":["calves","quadriceps","hamstrings","glutes","adductors"],"primary_motor_control_demands":["auditory_visual_reaction","perception_action_coupling","spatial_orientation","visual_navigation"],"postural_shape":"athletic stance with ribs stacked over pelvis during cuts and stops","breathing_demand":"rhythmic; no breath holding during approach, cut, or stop","balance_demand":"dynamic-high-speed","coordination_demand":"multi-step cone navigation with clean arm-leg timing","impact_level":2}'::jsonb, '{"movement_description":"Ball Drop/Point-and-Sprint Cone Reaction uses cones to create a clear movement problem: visual cue reaction into short acceleration. Athlete starts between cones; coach drops a ball or points to a cone target. The coach selects speed, spacing, and rest so the drill trains output rather than junk fatigue.","setup":["Athlete starts between cones; coach drops a ball or points to a cone target.","Use a flat, dry surface with at least 3-5 yards of safe run-out beyond the final cone.","Walk the route once so the athlete understands the entry, target, and finish standard."],"execution_steps":["Start in an athletic stance with eyes up and weight balanced through the whole foot.","Perform the ball drop/point-and-sprint cone reaction route at the prescribed speed while staying inside the cone constraints.","Brake, cut, or turn with hips loaded, knees tracking over toes, and the trunk under control.","Finish through the final cone or stick the final position exactly as prescribed.","Reset fully before the next rep; stop the set if posture, route accuracy, or braking quality fades."],"coach_cues":["Eyes up; see the cone early, not at the last step.","Push the ground away; do not reach and pull with the lead foot.","Load the hip before changing direction.","Quiet shoulders, violent arms when the drill calls for speed.","Win the shape before chasing the time."],"athlete_cues":["See it early.","Brake low and strong.","Push out of the cut.","Fast feet, quiet body."],"breathing_cues":["Breathe naturally during setup.","Do not hold the breath through the cut or stop.","Use one calm breath to reset before the next rep."],"common_faults":["Standing tall into the stop or cut.","Reaching the plant foot too far outside the hip.","Knee collapsing inside the foot.","Looking down at the cone instead of scanning ahead.","Turning quality reps into conditioning volume."],"quality_gate":["Route is correct without coach rescue.","Final stop or turn is balanced with no extra hop unless the drill calls for a run-through.","Knee tracks over toes on the plant leg.","Athlete can repeat the same shape on both sides.","Speed increases only after control is repeatable."],"stop_signs":["Pain in ankle, knee, hip, back, or groin.","Slipping surface or cones sliding into the athlete path.","Repeated uncontrolled knee valgus or trunk collapse.","Athlete cannot remember route or react safely.","Fatigue changes braking mechanics."]}'::jsonb),
  ('Commanded Pro Agility Shuttle', 'commanded-pro-agility-shuttle', 'Commanded Pro Agility Shuttle is a cone-based athletic drill focused on 5-10-5 pattern with left/right decision at the start. Standard 5-10-5 cone line; coach calls left or right on movement. It belongs in the library because it is easy to set up, easy to coach, and scalable from youth development to advanced field/court athletes.', 'INTERMEDIATE', 12, 3, 1, NULL, 120, 25, 'individual', 'Cone drill for 5-10-5 pattern with left/right decision at the start. Best when coached as Output with the drill dose matched to the session phase.', 'Primary phase: Output. Primary subrole: deceleration_cod_power. High intent, low volume, full rest; tired reps become conditioning rather than power. Progress only when the route, posture, and stop/cut quality are repeatable.', 'Attack the cone, brake under control, then explode out clean.', 'Reactive COD Test', 'output', 'deceleration_cod_power', 'reactive_cod_shuttle', '{"primary_joint_actions":["ankle_stiffness","hip_flexion_extension","knee_flexion_extension"],"primary_tissues":["calves","quadriceps","hamstrings","glutes","adductors"],"primary_motor_control_demands":["auditory_visual_reaction","perception_action_coupling","spatial_orientation","visual_navigation"],"postural_shape":"athletic stance with ribs stacked over pelvis during cuts and stops","breathing_demand":"rhythmic; no breath holding during approach, cut, or stop","balance_demand":"dynamic-high-speed","coordination_demand":"multi-step cone navigation with clean arm-leg timing","impact_level":4}'::jsonb, '{"movement_description":"Commanded Pro Agility Shuttle uses cones to create a clear movement problem: 5-10-5 pattern with left/right decision at the start. Standard 5-10-5 cone line; coach calls left or right on movement. The coach selects speed, spacing, and rest so the drill trains output rather than junk fatigue.","setup":["Standard 5-10-5 cone line; coach calls left or right on movement.","Use a flat, dry surface with at least 3-5 yards of safe run-out beyond the final cone.","Walk the route once so the athlete understands the entry, target, and finish standard."],"execution_steps":["Start in an athletic stance with eyes up and weight balanced through the whole foot.","Perform the commanded pro agility shuttle route at the prescribed speed while staying inside the cone constraints.","Brake, cut, or turn with hips loaded, knees tracking over toes, and the trunk under control.","Finish through the final cone or stick the final position exactly as prescribed.","Reset fully before the next rep; stop the set if posture, route accuracy, or braking quality fades."],"coach_cues":["Eyes up; see the cone early, not at the last step.","Push the ground away; do not reach and pull with the lead foot.","Load the hip before changing direction.","Quiet shoulders, violent arms when the drill calls for speed.","Win the shape before chasing the time."],"athlete_cues":["See it early.","Brake low and strong.","Push out of the cut.","Fast feet, quiet body."],"breathing_cues":["Breathe naturally during setup.","Do not hold the breath through the cut or stop.","Use one calm breath to reset before the next rep."],"common_faults":["Standing tall into the stop or cut.","Reaching the plant foot too far outside the hip.","Knee collapsing inside the foot.","Looking down at the cone instead of scanning ahead.","Turning quality reps into conditioning volume."],"quality_gate":["Route is correct without coach rescue.","Final stop or turn is balanced with no extra hop unless the drill calls for a run-through.","Knee tracks over toes on the plant leg.","Athlete can repeat the same shape on both sides.","Speed increases only after control is repeatable."],"stop_signs":["Pain in ankle, knee, hip, back, or groin.","Slipping surface or cones sliding into the athlete path.","Repeated uncontrolled knee valgus or trunk collapse.","Athlete cannot remember route or react safely.","Fatigue changes braking mechanics."]}'::jsonb),
  ('Cone Gauntlet Quality Intervals', 'cone-gauntlet-quality-intervals', 'Cone Gauntlet Quality Intervals is a cone-based athletic drill focused on repeat useful cone work under fatigue while maintaining posture. Use 4-6 cones to build a short route; work 15-25 seconds, rest fully enough to keep mechanics safe. It belongs in the library because it is easy to set up, easy to coach, and scalable from youth development to advanced field/court athletes.', 'INTERMEDIATE', 11, 5, NULL, 20, 60, 80, 'individual', 'Cone drill for repeat useful cone work under fatigue while maintaining posture. Best when coached as Sustained Capacity with the drill dose matched to the session phase.', 'Primary phase: Sustained Capacity. Primary subrole: conditioning_intervals. Conditioning on purpose late in the session; posture and safety cap the volume. Progress only when the route, posture, and stop/cut quality are repeatable.', 'Move fast enough to work, but clean enough to stay safe.', 'Cone Repeatability', 'sustained_capacity', 'conditioning_intervals', 'quality_agility_intervals', '{"primary_joint_actions":["ankle_stiffness","hip_flexion_extension","knee_flexion_extension"],"primary_tissues":["calves","quadriceps","hamstrings","glutes","adductors"],"primary_motor_control_demands":["spatial_orientation","visual_navigation"],"postural_shape":"athletic stance with ribs stacked over pelvis during cuts and stops","breathing_demand":"rhythmic; no breath holding during approach, cut, or stop","balance_demand":"dynamic","coordination_demand":"multi-step cone navigation with clean arm-leg timing","impact_level":3}'::jsonb, '{"movement_description":"Cone Gauntlet Quality Intervals uses cones to create a clear movement problem: repeat useful cone work under fatigue while maintaining posture. Use 4-6 cones to build a short route; work 15-25 seconds, rest fully enough to keep mechanics safe. The coach selects speed, spacing, and rest so the drill trains sustained capacity rather than junk fatigue.","setup":["Use 4-6 cones to build a short route; work 15-25 seconds, rest fully enough to keep mechanics safe.","Use a flat, dry surface with at least 3-5 yards of safe run-out beyond the final cone.","Walk the route once so the athlete understands the entry, target, and finish standard.","Place this late in the session and set a quality cap before starting."],"execution_steps":["Start in an athletic stance with eyes up and weight balanced through the whole foot.","Move for the prescribed work interval while preserving posture, foot control, and route accuracy.","Brake, cut, or turn with hips loaded, knees tracking over toes, and the trunk under control.","Finish through the final cone or stick the final position exactly as prescribed.","End the interval early if the athlete can no longer brake or turn safely."],"coach_cues":["Eyes up; see the cone early, not at the last step.","Push the ground away; do not reach and pull with the lead foot.","Load the hip before changing direction.","Quiet shoulders, violent arms when the drill calls for speed.","Win the shape before chasing the time."],"athlete_cues":["See it early.","Brake low and strong.","Push out of the cut.","Fast feet, quiet body."],"breathing_cues":["Breathe naturally during setup.","Do not hold the breath through the cut or stop.","Use one calm breath to reset before the next rep."],"common_faults":["Standing tall into the stop or cut.","Reaching the plant foot too far outside the hip.","Knee collapsing inside the foot.","Looking down at the cone instead of scanning ahead.","Turning quality reps into conditioning volume."],"quality_gate":["Route is correct without coach rescue.","Final stop or turn is balanced with no extra hop unless the drill calls for a run-through.","Knee tracks over toes on the plant leg.","Athlete can repeat the same shape on both sides.","Speed increases only after control is repeatable."],"stop_signs":["Pain in ankle, knee, hip, back, or groin.","Slipping surface or cones sliding into the athlete path.","Repeated uncontrolled knee valgus or trunk collapse.","Athlete cannot remember route or react safely.","Fatigue changes braking mechanics."]}'::jsonb)
) AS d(name, slug, description, skill, age_min, sets, reps, work, rest, est, participant, summary, coach_lang, athlete_lang, family, phase_key, subrole, slot, req, exec)
CROSS JOIN public.facility f
