INSERT INTO coaching.exercise_phase_profile (
  exercise_id, phase_id, fit_weight, role, order_slot, order_index,
  freshness_required, fatigue_sensitivity, fatigue_cost, technical_complexity, impact_level, intensity_ceiling
)
SELECT e.id, sp.id, COALESCE(m.fit_weight, 5), COALESCE(m.role, 'primary'), m.slot, pos.order_index,
  COALESCE(m.freshness_required, FALSE), COALESCE(m.fatigue_sensitivity, 3), COALESCE(m.fatigue_cost, 3),
  COALESCE(m.technical_complexity, 3), COALESCE(m.impact_level, 0), COALESCE(m.intensity_ceiling, 'high')
FROM (VALUES
  ('cone-march-line', 'movement_intelligence', 'cone_sprint_mechanics', 'primary', 5, TRUE, 3, 2, 2, 1, 'moderate'),
  ('cone-skip-rhythm-build', 'movement_intelligence', 'cone_skip_rhythm', 'primary', 5, TRUE, 3, 2, 2, 2, 'moderate'),
  ('a-skip-through-cone-gates', 'movement_intelligence', 'cone_sprint_mechanics', 'primary', 5, TRUE, 3, 2, 2, 2, 'moderate'),
  ('falling-start-to-10-yard-cone', 'output', 'short_acceleration_start', 'primary', 5, TRUE, 4, 4, 2, 3, 'high'),
  ('split-stance-10-yard-acceleration', 'output', 'short_acceleration_start', 'primary', 5, TRUE, 4, 4, 2, 3, 'high'),
  ('push-up-start-to-cone', 'output', 'ground_start_acceleration', 'primary', 5, TRUE, 4, 4, 3, 3, 'high'),
  ('crossover-step-to-sprint-cone', 'output', 'lateral_start_acceleration', 'primary', 5, TRUE, 4, 4, 3, 3, 'high'),
  ('curve-run-around-cone-arc', 'movement_intelligence', 'curvilinear_sprint_mechanics', 'primary', 5, TRUE, 3, 2, 2, 2, 'moderate'),
  ('20-20-20-build-up-sprint', 'output', 'build_up_speed_exposure', 'primary', 5, TRUE, 4, 4, 2, 3, 'high'),
  ('fly-zone-cone-sprint', 'output', 'fly_sprint_exposure', 'primary', 5, TRUE, 4, 4, 3, 3, 'high'),
  ('45-degree-cut-and-stick', 'resilience', 'angle_cut_stick', 'primary', 5, FALSE, 3, 3, 2, 3, 'moderate'),
  ('90-degree-cut-and-stick', 'resilience', 'angle_cut_stick', 'primary', 5, FALSE, 3, 3, 2, 3, 'moderate'),
  ('decel-to-reaccelerate-gate', 'output', 'decel_reacceleration_gate', 'primary', 5, TRUE, 4, 4, 3, 3, 'high'),
  ('single-leg-cone-reach-stick', 'resilience', 'single_leg_cone_reach', 'primary', 5, FALSE, 3, 3, 2, 1, 'moderate'),
  ('closeout-chop-to-stick', 'resilience', 'chop_to_stick', 'primary', 5, FALSE, 3, 3, 2, 2, 'moderate'),
  ('drop-step-decel-cone-box', 'output', 'drop_step_decel_reaccelerate', 'primary', 5, TRUE, 4, 4, 3, 3, 'high'),
  ('shuffle-sprint-brake-combo', 'output', 'combo_deceleration', 'primary', 5, TRUE, 4, 4, 3, 3, 'high'),
  ('5-10-5-pro-agility-shuttle', 'output', 'planned_cod_test', 'primary', 5, TRUE, 4, 4, 3, 4, 'high'),
  ('3-cone-l-drill', 'output', 'planned_cod_test', 'primary', 5, TRUE, 4, 4, 4, 4, 'high'),
  ('t-test-agility-drill', 'output', 'planned_cod_test', 'primary', 5, TRUE, 4, 4, 3, 3, 'high'),
  ('w-drill-forward-cuts', 'output', 'planned_cod_pattern', 'primary', 5, TRUE, 4, 4, 2, 3, 'high'),
  ('w-drill-backpedal-cuts', 'movement_intelligence', 'planned_multidirectional_pattern', 'primary', 5, TRUE, 3, 2, 2, 2, 'moderate'),
  ('box-drill-sprint-shuffle-backpedal', 'movement_intelligence', 'planned_multidirectional_pattern', 'primary', 5, TRUE, 3, 2, 2, 2, 'moderate'),
  ('x-drill-cone-cut', 'output', 'planned_cod_pattern', 'primary', 5, TRUE, 4, 4, 3, 3, 'high'),
  ('m-drill-multidirectional-cut', 'movement_intelligence', 'planned_multidirectional_pattern', 'primary', 5, TRUE, 3, 2, 2, 2, 'moderate'),
  ('u-drill-turn-and-go', 'output', 'planned_cod_pattern', 'primary', 5, TRUE, 4, 4, 2, 3, 'high'),
  ('illinois-agility-run', 'output', 'planned_cod_test', 'primary', 5, TRUE, 4, 4, 4, 4, 'high'),
  ('slalom-weave-run', 'movement_intelligence', 'weave_spatial_control', 'primary', 5, TRUE, 3, 2, 2, 2, 'moderate'),
  ('zig-zag-sprint-cuts', 'output', 'angle_cut_series', 'primary', 5, TRUE, 4, 4, 2, 3, 'high'),
  ('circle-cone-chase', 'movement_intelligence', 'curvilinear_reactive_game', 'primary', 5, TRUE, 3, 2, 2, 2, 'moderate'),
  ('hexagon-cone-attack-drill', 'movement_intelligence', 'multidirectional_spatial_control', 'primary', 5, TRUE, 3, 2, 2, 2, 'moderate'),
  ('4-corner-cone-touch-drill', 'movement_intelligence', 'multidirectional_spatial_control', 'primary', 5, TRUE, 3, 2, 2, 1, 'moderate'),
  ('star-drill-return-to-center', 'movement_intelligence', 'multidirectional_spatial_control', 'primary', 5, TRUE, 3, 2, 2, 2, 'moderate'),
  ('5-cone-compass-drill', 'movement_intelligence', 'multidirectional_spatial_control', 'primary', 5, TRUE, 3, 2, 2, 1, 'moderate'),
  ('triangle-shuffle-sprint-drill', 'movement_intelligence', 'planned_multidirectional_pattern', 'primary', 5, TRUE, 3, 2, 2, 2, 'moderate'),
  ('serpentine-sprint-to-backpedal-drill', 'movement_intelligence', 'weave_spatial_control', 'primary', 5, TRUE, 3, 2, 2, 2, 'moderate'),
  ('partner-mirror-shuffle-box', 'movement_intelligence', 'partner_mirror_agility', 'primary', 5, TRUE, 3, 2, 2, 2, 'moderate'),
  ('partner-crossover-mirror-box', 'movement_intelligence', 'partner_mirror_agility', 'primary', 5, TRUE, 3, 2, 3, 2, 'moderate'),
  ('5-cone-chase-drill', 'output', 'partner_chase_reactive_output', 'primary', 5, TRUE, 4, 4, 3, 3, 'high'),
  ('coach-call-out-4-cone-box', 'output', 'coach_callout_reactive_output', 'primary', 5, TRUE, 4, 4, 2, 2, 'high'),
  ('color-number-cone-reaction-drill', 'movement_intelligence', 'coach_callout_reactive_skill', 'primary', 5, TRUE, 3, 2, 2, 1, 'moderate'),
  ('reactive-box-shuttle', 'output', 'reactive_box_shuttle', 'primary', 5, TRUE, 4, 4, 3, 3, 'high'),
  ('shadow-tag-cone-channel', 'movement_intelligence', 'partner_tag_agility', 'primary', 5, TRUE, 3, 2, 2, 2, 'moderate'),
  ('ball-drop-point-and-sprint-cone-reaction', 'output', 'visual_reaction_acceleration', 'primary', 5, TRUE, 4, 4, 2, 2, 'high'),
  ('commanded-pro-agility-shuttle', 'output', 'reactive_cod_shuttle', 'primary', 5, TRUE, 4, 4, 4, 4, 'high'),
  ('cone-gauntlet-quality-intervals', 'sustained_capacity', 'quality_agility_intervals', 'primary', 5, FALSE, 3, 4, 2, 3, 'moderate')
) AS m(slug, phase_key, slot, role, fit_weight, freshness_required, fatigue_sensitivity, fatigue_cost, technical_complexity, impact_level, intensity_ceiling)
JOIN coaching.exercise e ON e.slug = m.slug
JOIN coaching.session_phase sp ON sp.key = m.phase_key
JOIN coaching.phase_order_slot pos ON pos.key = m.slot AND pos.phase_id = sp.id
ON CONFLICT (exercise_id, phase_id) DO UPDATE SET
  role = EXCLUDED.role, order_slot = EXCLUDED.order_slot, fit_weight = EXCLUDED.fit_weight,
  freshness_required = EXCLUDED.freshness_required, fatigue_sensitivity = EXCLUDED.fatigue_sensitivity,
  fatigue_cost = EXCLUDED.fatigue_cost, technical_complexity = EXCLUDED.technical_complexity,
  impact_level = EXCLUDED.impact_level, intensity_ceiling = EXCLUDED.intensity_ceiling;

